const actors = new Set(canvas.tokens.controlled.map(t => t.actor).filter(a => a.type === 'hero'));

if (actors.size === 0) return ui.notifications.warn('HONOR_INTRIGUE.Dialog.Result.NoHeroesSelected', { localize: true });

const fields = foundry.applications.fields;
const data = await foundry.applications.api.DialogV2.input({
  window: { title: 'HONOR_INTRIGUE.Dialog.AwardAdvancementPoints.Title' },
  content: fields.createFormGroup({
    input: fields.createNumberInput({ name: 'pointsInput', value: 1 }),
    label: game.i18n.localize('HONOR_INTRIGUE.Dialog.AwardAdvancementPoints.Label')
  }).outerHTML,
  ok: {
    label: 'HONOR_INTRIGUE.Dialog.AwardAdvancementPoints.ButtonAward',
    icon: 'fa-solid fa-arrow-up'
  }
});

if (!data || !data.pointsInput) return;

await Promise.all(actors.map(async (actor) => actor.update({ 'system.advancementPoints.value': actor.system.advancementPoints.value + data.pointsInput })));
